  ('aboriginal-6f0ba476-moex-00341', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', 'A公司因當年度淨利較上年度大幅下降，於辦理當年度營利事業所得稅暫繳時，欲適用所得稅法 規定按當年度前6個月所得計算暫繳稅額，有關該規定適用要件，下列何者錯誤？', '["須向稽徵機關申請核准", "如期辦理暫繳申報", "會計帳冊簿據完備", "使用藍色申報書或經會計師查核簽核"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
