  ('aboriginal-6f0ba476-moex-00343', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', 'A公司總機構設於新北市，當年度有國內課稅所得額500萬元及日本分公司稅前所得300萬元，該 分公司於日本已繳納所得稅70萬元；另有荷蘭子公司稅前所得400萬元，該子公司於荷蘭已繳納所 得稅60萬元，但尚未發股利給A公司。當年度A公司應繳納我國多少之營利事業所得稅？', '["85萬元", "90萬元", "100萬元", "110萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
