  ('aboriginal-6f0ba476-moex-00347', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '各稅課關於農地移轉之減免規定，下列敘述何者正確？', '["遺產中作農業使用之農業用地及其地上農作物，由法定繼承人承受者，不計入遺產總額", "作農業使用之農業用地及其地上農作物，贈與法定繼承人者，不計入贈與總額", "作農業使用之農業用地，贈與法定繼承人者，免徵土地增值稅", "作農業使用之農業用地移轉免徵土地增值稅、遺產稅或贈與稅者，承受人自承受之日起，如未 將該土地繼續作農業使用，應追繳應納稅賦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
